// Extract user message from webhook body
const msg = $json.body?.message ?? $json.message ?? "";
const message = msg.toString().trim() || "hello";

// Preserve message cleanly
$json.message = message;
$json.user_msg = message;

// History does NOT get appended here anymore
// (history will be handled later per session)

return $json;

const store = $getWorkflowStaticData('global');

// Read session + user message (from earlier nodes)
const sid = ($json.session_id ?? $json.body?.session_id ?? "no-session").toString();
const userMsg = ($json.user_msg ?? $json.message ?? $json.body?.message ?? "").toString();

// Get assistant reply (Basic LLM Chain usually outputs `text`)
const botMsg =
  $json.text ||
  $json.output?.text ||
  $json.output ||
  $json.result ||
  $json.reply ||
  "no response";

// Load previous stored history for this session
const prev = store[sid]?.history || [];

// Append new turn
const newHistory = [
  ...prev,
  { role: "user", content: userMsg },
  { role: "assistant", content: botMsg },
].slice(-20);

// Save back
store[sid] = store[sid] || {};
store[sid].history = newHistory;

// Expose for response / next nodes
$json.history = newHistory;
$json.reply = botMsg;
$json.text = botMsg;
$json.session_id = sid;

return {
  session_id: sid,
  reply: botMsg,
  // history: newHistory,  // optional
  user_name: $json.user_name, // optional
};

// Normalize incoming payload whether n8n puts it in $json.body or top-level
const body = $json.body ?? $json;

// session_id
let session_id = (body.session_id ?? $json.session_id ?? "").toString().trim();
if (!session_id) {
  session_id = Date.now().toString(36) + Math.random().toString(36).slice(2, 10);
}

// latest user message
const message = (body.message ?? $json.message ?? "").toString();

// full chat history from WP (DB)
const messages = Array.isArray(body.messages) ? body.messages : [];

// Return a CLEAN object: no duplicates, no nested body
return {
  session_id,
  message,
  user_msg: message,
  messages
};
